// ============================================
// CLIENT CONFIGURATION - EDIT THIS SECTION
// ============================================
const CLIENT_NAME = 'Codesec Technologies';
const CLIENT_ADDRESS = 'Chennai, Tamil Nadu, India';
const REPORT_EMAIL = 'naveen@codesecure.in';
const MANAGER_NAME = 'ip-192-168-133-24';
const OPENSEARCH_URL = 'https://172.17.0.1:9200';
const OPENSEARCH_AUTH = 'Basic YWRtaW46bXBwN05ITk9tU3k4Y0FjMmlBcCpBaGdVYUU3aytsVEI=';
const CLIENT_LOGO = 'https://codesecure.in/images/codesec-logo1.png';
// ============================================

return [{
  json: {
    client_name: CLIENT_NAME,
    client_address: CLIENT_ADDRESS,
    report_email: REPORT_EMAIL,
    manager_name: MANAGER_NAME,
    opensearch_url: OPENSEARCH_URL,
    opensearch_auth: OPENSEARCH_AUTH,
    client_logo: CLIENT_LOGO
  }
}];

const config = $('Client Config').first().json;
const data = $input.first().json;
const aggs = data.aggregations.today;
const totalHits = aggs.doc_count;
const prevDayTotal = data.aggregations.prev_day_total.doc_count;
const prevDayLevels = (data.aggregations.prev_day_by_level.levels||{buckets:[]}).buckets;

const now = new Date();
const istOpt = { timeZone: 'Asia/Kolkata' };
const istDate = now.toLocaleDateString('en-IN', { ...istOpt, day:'2-digit', month:'2-digit', year:'numeric' });
const istTime = now.toLocaleTimeString('en-IN', { ...istOpt, hour12:true, hour:'2-digit', minute:'2-digit' });
const yesterday = new Date(now - 86400000);
const fromDate = yesterday.toLocaleDateString('en-IN', { ...istOpt, day:'2-digit', month:'short', year:'numeric' }) + ' ' + yesterday.toLocaleTimeString('en-IN', { ...istOpt, hour:'2-digit', minute:'2-digit', hour12:true });
const toDate = now.toLocaleDateString('en-IN', { ...istOpt, day:'2-digit', month:'short', year:'numeric' }) + ' ' + now.toLocaleTimeString('en-IN', { ...istOpt, hour:'2-digit', minute:'2-digit', hour12:true });

// WAZUH OFFICIAL severity mapping
// Critical: level >= 15 | High: 12-14 | Medium: 7-11 | Low: 0-6
const levelBuckets = aggs.alerts_by_level.buckets;
const severityCounts = { Critical:0, High:0, Medium:0, Low:0 };
levelBuckets.forEach(b => {
  const lvl = b.key;
  if (lvl >= 15) severityCounts.Critical += b.doc_count;
  else if (lvl >= 12) severityCounts.High += b.doc_count;
  else if (lvl >= 7) severityCounts.Medium += b.doc_count;
  else severityCounts.Low += b.doc_count;
});

const topRules = aggs.top_rules.buckets.map(b => ({
  rule_id: b.key,
  description: b.rule_desc.buckets[0]?.key || 'N/A',
  level: b.rule_level.buckets[0]?.key || 0,
  count: b.doc_count
})).sort((a,b) => b.level-a.level || b.count-a.count);

const topAgents = aggs.top_agents.buckets.map(b => {
  const levels = (b.by_level||{buckets:[]}).buckets;
  let crit=0,high=0,med=0,low=0;
  levels.forEach(l=>{ if(l.key>=15)crit+=l.doc_count; else if(l.key>=12)high+=l.doc_count; else if(l.key>=7)med+=l.doc_count; else low+=l.doc_count; });
  return { name:b.key, count:b.doc_count, critical:crit, high:high, medium:med, low:low };
});
const mitreTechniques = aggs.mitre_techniques.buckets.map(b => ({ technique:b.key, count:b.doc_count }));
const mitreTactics = aggs.mitre_tactics.buckets.map(b => ({ tactic:b.key, count:b.doc_count }));
const timeline = aggs.alerts_over_time.buckets.map(b => ({
  hour: new Date(b.key_as_string).toLocaleTimeString('en-IN', { timeZone:'Asia/Kolkata', hour:'2-digit', minute:'2-digit', hour12:false }),
  count: b.doc_count
}));

return [{ json: {
  client_name: config.client_name, client_address: config.client_address,
  report_email: config.report_email, manager_name: config.manager_name,
  client_logo: config.client_logo, total_alerts: totalHits,
  severity_counts: severityCounts, top_rules: topRules,
  top_agents: topAgents, mitre_techniques: mitreTechniques,
  mitre_tactics: mitreTactics, timeline: timeline,
  auth_fail_count: aggs.auth_fail.doc_count,
  auth_fail_users: [...(aggs.auth_fail.by_win_user||{buckets:[]}).buckets.map(b=>({user:b.key,count:b.doc_count})),...(aggs.auth_fail.by_dstuser||{buckets:[]}).buckets.filter(b=>b.key!=='-'&&b.key!=='').map(b=>({user:b.key,count:b.doc_count})),...(aggs.auth_fail.by_srcuser||{buckets:[]}).buckets.filter(b=>b.key!=='-'&&b.key!=='').map(b=>({user:b.key,count:b.doc_count}))].reduce((acc,x)=>{const e=acc.find(a=>a.user===x.user);if(e)e.count=Math.max(e.count,x.count);else acc.push(x);return acc;},[]).sort((a,b)=>b.count-a.count).slice(0,5),
  auth_fail_ips: [...(aggs.auth_fail.by_win_ip||{buckets:[]}).buckets.map(b=>({ip:b.key,count:b.doc_count})),...(aggs.auth_fail.by_srcip||{buckets:[]}).buckets.filter(b=>b.key!=='-'&&b.key!=='').map(b=>({ip:b.key,count:b.doc_count}))].reduce((acc,x)=>{const e=acc.find(a=>a.ip===x.ip);if(e)e.count=Math.max(e.count,x.count);else acc.push(x);return acc;},[]).sort((a,b)=>b.count-a.count).slice(0,5),
  auth_fail_events: (aggs.auth_fail.top_rules||{buckets:[]}).buckets.map(b=>({desc:b.key,count:b.doc_count})),
  auth_success_count: aggs.auth_success.doc_count,
  auth_success_users: [...(aggs.auth_success.by_win_user||{buckets:[]}).buckets.map(b=>({user:b.key,count:b.doc_count})),...(aggs.auth_success.by_dstuser||{buckets:[]}).buckets.filter(b=>b.key!=='-'&&b.key!=='').map(b=>({user:b.key,count:b.doc_count})),...(aggs.auth_success.by_srcuser||{buckets:[]}).buckets.filter(b=>b.key!=='-'&&b.key!=='').map(b=>({user:b.key,count:b.doc_count}))].reduce((acc,x)=>{const e=acc.find(a=>a.user===x.user);if(e)e.count=Math.max(e.count,x.count);else acc.push(x);return acc;},[]).sort((a,b)=>b.count-a.count).slice(0,5),
  auth_success_events: (aggs.auth_success.top_rules||{buckets:[]}).buckets.map(b=>({desc:b.key,count:b.doc_count})),
  vuln_total: aggs.vuln.doc_count,
  vuln_by_sev: (aggs.vuln.by_sev||{buckets:[]}).buckets.map(b=>({severity:b.key,count:b.doc_count})),
  vuln_top_cve: (aggs.vuln.top_cve||{buckets:[]}).buckets.map(b=>({cve:b.key,count:b.doc_count})),
  vuln_top_agent: (aggs.vuln.top_agent||{buckets:[]}).buckets.map(b=>({agent:b.key,count:b.doc_count})),
  vuln_top_pkg: (aggs.vuln.top_pkg||{buckets:[]}).buckets.map(b=>({pkg:b.key,count:b.doc_count})),
  level12_count: aggs.level12.doc_count,
  sca_total: aggs.sca.doc_count,
  sca_results: (aggs.sca.by_result||{buckets:[]}).buckets.map(b=>({result:b.key,count:b.doc_count})),
  sca_policies: (aggs.sca.by_policy||{buckets:[]}).buckets.map(b=>({policy:b.key,count:b.doc_count})),
  fim_total: aggs.fim.doc_count,
  fim_events: (aggs.fim.by_event||{buckets:[]}).buckets.map(b=>({event:b.key,count:b.doc_count})),
  fim_agents: (aggs.fim.by_agent||{buckets:[]}).buckets.map(b=>({agent:b.key,count:b.doc_count})),
  fim_paths: (aggs.fim.by_path||{buckets:[]}).buckets.map(b=>({path:b.key,count:b.doc_count})),
  prev_day_total: prevDayTotal,
  prev_day_severity: (()=>{ const s={Critical:0,High:0,Medium:0,Low:0}; prevDayLevels.forEach(b=>{ if(b.key>=15)s.Critical+=b.doc_count; else if(b.key>=12)s.High+=b.doc_count; else if(b.key>=7)s.Medium+=b.doc_count; else s.Low+=b.doc_count; }); return s; })(),
  recommendations: (()=>{
    const recs = [];
    if(severityCounts.Critical>0) recs.push({icon:'!!',color:'#BD271E',text:''+severityCounts.Critical+' critical alerts detected. Investigate immediately and validate if these are true positives.'});
    if(severityCounts.High>50) recs.push({icon:'!',color:'#E7664C',text:'High volume of high-severity alerts ('+severityCounts.High.toLocaleString()+'). Review alert rules and tune false positives.'});
    const authFail = aggs.auth_fail.doc_count;
    if(authFail>100) recs.push({icon:'X',color:'#e74c3c',text:''+authFail.toLocaleString()+' authentication failures detected. Review failed login sources and consider IP blocking or account lockout policies.'});
    const vulnTotal = aggs.vuln.doc_count;
    if(vulnTotal>0) recs.push({icon:'V',color:'#e67e22',text:''+vulnTotal.toLocaleString()+' vulnerability alerts. Prioritize patching critical and high severity CVEs on affected agents.'});
    const scaFailed = ((aggs.sca.by_result||{buckets:[]}).buckets.find(b=>b.key==='failed')||{doc_count:0}).doc_count;
    if(scaFailed>0) recs.push({icon:'C',color:'#9b59b6',text:''+scaFailed+' SCA compliance checks failed. Review and remediate to improve security posture.'});
    if(topAgents.length>0 && topAgents[0].count > totalHits*0.3) recs.push({icon:'A',color:'#3498db',text:'Agent '+topAgents[0].name+' generates '+((topAgents[0].count/totalHits)*100).toFixed(0)+'% of all alerts. Investigate if misconfigured or under attack.'});
    if(recs.length===0) recs.push({icon:'OK',color:'#2ecc71',text:'No critical recommendations. Continue monitoring and maintain current security posture.'});
    return recs;
  })(),
  agent_risk: topAgents.map(a=>{
    const total = a.count||1;
    const critPct = (a.critical/total)*100;
    const highPct = (a.high/total)*100;
    const medPct = (a.medium/total)*100;
    const score = Math.min(100, Math.round(critPct*4 + highPct*2 + medPct*0.3));
    let risk,note;
    if(a.critical>0){risk='Critical';note=a.critical+' critical alerts - investigate immediately';}
    else if(a.high>10){risk='High';note=a.high+' high severity alerts - review required';}
    else if(score>=30){risk='Medium';note='Elevated alert volume - monitor closely';}
    else {risk='Low';note='Normal activity - routine monitoring';}
    return { name:a.name, count:a.count, critical:a.critical, high:a.high, medium:a.medium, low:a.low, score:score, risk:risk, note:note };
  }).sort((a,b)=>b.score-a.score),
  from_date: fromDate, to_date: toDate, ist_date: istDate, ist_time: istTime
}}];

const d = $input.first().json;
const sc = d.severity_counts;

// Wazuh official severity colors
const sevDef = [
  { key:'Critical', color:'#BD271E', range:'Level 15+' },
  { key:'High', color:'#E7664C', range:'Level 12-14' },
  { key:'Medium', color:'#D6BF57', range:'Level 7-11' },
  { key:'Low', color:'#6DCCB1', range:'Level 0-6' }
];

// SVG Donut
function svgDonut(data, w, h, r, r2) {
  const cx=w/2, cy=h/2;
  const total = data.reduce((s,x)=>s+x.value,0)||1;
  let cum=-90; const paths=data.filter(x=>x.value>0).map(x=>{
    const pct=x.value/total, ang=pct*360;
    const s=cum*Math.PI/180, e=(cum+ang)*Math.PI/180; cum+=ang;
    const la=ang>180?1:0;
    const x1=cx+r*Math.cos(s),y1=cy+r*Math.sin(s);
    const x2=cx+r*Math.cos(e),y2=cy+r*Math.sin(e);
    const x3=cx+r2*Math.cos(e),y3=cy+r2*Math.sin(e);
    const x4=cx+r2*Math.cos(s),y4=cy+r2*Math.sin(s);
    return `<path d="M${x1},${y1} A${r},${r} 0 ${la},1 ${x2},${y2} L${x3},${y3} A${r2},${r2} 0 ${la},0 ${x4},${y4}Z" fill="${x.color}"/>`;
  }).join('');
  return `<svg width="${w}" height="${h}" viewBox="0 0 ${w} ${h}">${paths}<text x="${cx}" y="${cy-6}" text-anchor="middle" font-size="18" font-weight="800" fill="#2c3e50">${total.toLocaleString()}</text><text x="${cx}" y="${cy+10}" text-anchor="middle" font-size="9" fill="#95a5a6">Total Alerts</text></svg>`;
}

// SVG Vertical bars
function svgVBars(items, w, h) {
  const pad={t:15,b:40,l:5,r:5};
  const cW=w-pad.l-pad.r, cH=h-pad.t-pad.b;
  const max=Math.max(...items.map(i=>i.value),1);
  const bW=Math.min(Math.floor(cW/items.length)-2,22);
  const gap=(cW-bW*items.length)/(items.length+1);
  let s='';
  items.forEach((it,i)=>{
    const bH=Math.max((it.value/max)*cH,2);
    const x=pad.l+gap+(bW+gap)*i, y=pad.t+cH-bH;
    s+=`<rect x="${x}" y="${y}" width="${bW}" height="${bH}" fill="${it.color||'#3498db'}" rx="2"/>`;
    s+=`<text x="${x+bW/2}" y="${pad.t+cH+12}" text-anchor="middle" font-size="5.5" fill="#7f8c8d" transform="rotate(50,${x+bW/2},${pad.t+cH+12})">${it.label}</text>`;
    s+=`<text x="${x+bW/2}" y="${y-4}" text-anchor="middle" font-size="5.5" fill="#555">${it.value>=1000000?(it.value/1000000).toFixed(1)+'M':it.value>=1000?(it.value/1000).toFixed(0)+'k':it.value}</text>`;
  });
  s+=`<line x1="${pad.l}" y1="${pad.t+cH}" x2="${w-pad.r}" y2="${pad.t+cH}" stroke="#ecf0f1" stroke-width="1"/>`;
  return `<svg width="${w}" height="${h}" viewBox="0 0 ${w} ${h}">${s}</svg>`;
}

// SVG Horizontal bars
function svgHBars(items, w, h) {
  const pad={t:5,b:5,l:110,r:55};
  const cW=w-pad.l-pad.r;
  const bH=Math.min(Math.floor((h-pad.t-pad.b)/items.length)-3,16);
  const max=Math.max(...items.map(i=>i.value),1);
  let s='';
  items.forEach((it,i)=>{
    const bw=Math.max((it.value/max)*cW,3);
    const y=pad.t+(bH+3)*i;
    s+=`<text x="${pad.l-5}" y="${y+bH/2+3}" text-anchor="end" font-size="7" fill="#2c3e50">${it.label.length>16?it.label.substring(0,16)+'..':it.label}</text>`;
    s+=`<rect x="${pad.l}" y="${y}" width="${bw}" height="${bH}" fill="${it.color||'#3498db'}" rx="3"/>`;
    s+=`<text x="${pad.l+bw+4}" y="${y+bH/2+3}" font-size="7" font-weight="700" fill="#2c3e50">${it.value.toLocaleString()}</text>`;
  });
  return `<svg width="${w}" height="${h}" viewBox="0 0 ${w} ${h}">${s}</svg>`;
}

const palette = ['#2ecc71','#3498db','#9b59b6','#e67e22','#1abc9c','#e74c3c','#f39c12','#2980b9','#8e44ad','#16a085','#e91e63','#00bcd4','#8bc34a','#ff5722','#607d8b'];

// Build charts
const donutSvg = svgDonut(sevDef.map(s=>({value:sc[s.key],color:s.color})), 180, 180, 70, 45);
const donutLegend = sevDef.map(s=>`<div style="display:flex;align-items:center;margin:4px 0"><div style="width:14px;height:14px;border-radius:3px;background:${s.color};margin-right:8px"></div><div><div style="font-size:10px;font-weight:700">${s.key}</div><div style="font-size:8px;color:#95a5a6">${s.range}: ${sc[s.key].toLocaleString()}</div></div></div>`).join('');

const timelineSvg = svgVBars(d.timeline.map(t=>({value:t.count,label:t.hour,color:'#3498db'})), 500, 150);
const agentSvg = svgHBars(d.top_agents.map((a,i)=>({value:a.count,label:a.name,color:palette[i%15]})), 500, Math.max(d.top_agents.length*19+10,80));
const techSvg = svgHBars(d.mitre_techniques.map((m,i)=>({value:m.count,label:m.technique,color:palette[i%15]})), 500, Math.max(d.mitre_techniques.length*19+10,80));
const tacticSvg = svgHBars(d.mitre_tactics.map((m,i)=>({value:m.count,label:m.tactic,color:palette[i%15]})), 500, Math.max(d.mitre_tactics.length*19+10,80));

// Severity stat cards (matching Wazuh dashboard style)
const statCards = sevDef.map(s=>{
  const txtColor = s.key==='Critical'?'#BD271E':s.key==='High'?'#E7664C':s.key==='Medium'?'#D6BF57':'#6DCCB1';
  return `<div style="flex:1;text-align:center;padding:14px 6px;border-radius:8px;border:1px solid #ecf0f1;background:#fafbfc"><div style="font-size:10px;font-weight:600;color:#69707D;margin-bottom:6px">${s.key} severity</div><div style="font-size:26px;font-weight:800;color:${txtColor}">${sc[s.key].toLocaleString()}</div><div style="font-size:8px;color:#98A2B3;margin-top:3px">${s.range}</div></div>`;
}).join('');

// Alerts table sorted by level desc
const sortedRules = [...d.top_rules].sort((a,b)=>b.level-a.level||b.count-a.count);
const ruleRows = sortedRules.map((r,i)=>{
  const lc = r.level>=15?'#BD271E':r.level>=12?'#E7664C':r.level>=7?'#D6BF57':'#6DCCB1';
  const bg = i%2===0?'#fff':'#f8f9fb';
  return `<tr style="background:${bg};border-left:3px solid ${lc}"><td style="padding:3px 6px;border-bottom:1px solid #ecf0f1;text-align:center;font-weight:700;color:#2c3e50;font-size:8px">${r.rule_id}</td><td style="padding:3px 6px;border-bottom:1px solid #ecf0f1;font-size:7.5px;color:#34495e">${r.description.length>95?r.description.substring(0,95)+'...':r.description}</td><td style="padding:5px 8px;border-bottom:1px solid #ecf0f1;text-align:center"><span style="background:${lc};color:#fff;padding:2px 8px;border-radius:10px;font-size:7px;font-weight:700">${r.level}</span></td><td style="padding:3px 6px;border-bottom:1px solid #ecf0f1;text-align:right;font-weight:700;color:#2c3e50;font-size:8px">${r.count.toLocaleString()}</td></tr>`;
}).join('');

const logoImg = d.client_logo ? `<img src="${d.client_logo}" style="height:60px;display:block;margin-bottom:16px" onerror="this.style.display='none'"/>` : '';
// No logo in footer - only on cover page

