  <div class="card"><div class="stitle"><span class="dot" style="background:#9b59b6"></span>Policies Evaluated</div>${d.sca_policies.length>0?'<table><thead><tr><th>Policy</th><th style="text-align:right;padding-right:10px">Checks</th></tr></thead><tbody>'+d.sca_policies.map((p,i)=>'<tr style="background:'+(i%2===0?'#fff':'#f8f9fb')+'"><td style="padding:4px 8px;border-bottom:1px solid #ecf0f1;font-size:8px">'+p.policy+'</td><td style="padding:4px 8px;border-bottom:1px solid #ecf0f1;text-align:right;font-weight:700;font-size:8px">'+p.count.toLocaleString()+'</td></tr>').join('')+'</tbody></table>':'<div style="text-align:center;color:#95a5a6;font-size:9px;padding:20px">No SCA data in this period</div>'}</div>
</div>

<!-- PAGE: File Integrity Monitoring -->
<div class="page">
