    ${d.fim_events.map(e=>{ const ec=e.event==='deleted'?'#e74c3c':e.event==='added'?'#2ecc71':e.event==='modified'?'#e67e22':'#3498db'; return '<div style="flex:1;text-align:center;padding:16px;border-radius:8px;border:1px solid #ecf0f1;background:#fafbfc"><div style="font-size:28px;font-weight:800;color:'+ec+'">'+e.count.toLocaleString()+'</div><div style="font-size:9px;color:#69707D;margin-top:4px">'+e.event.charAt(0).toUpperCase()+e.event.slice(1)+'</div></div>'; }).join('')}
