    <div class="card" style="flex:1"><div class="stitle"><span class="dot" style="background:#e67e22"></span>Top Modified Paths</div>${d.fim_paths.length>0?'<table><thead><tr><th>File Path</th><th style="text-align:right;padding-right:10px">Count</th></tr></thead><tbody>'+d.fim_paths.map((p,i)=>'<tr style="background:'+(i%2===0?'#fff':'#f8f9fb')+'"><td style="padding:4px 8px;border-bottom:1px solid #ecf0f1;font-size:7px;font-family:monospace">'+p.path+'</td><td style="padding:4px 8px;border-bottom:1px solid #ecf0f1;text-align:right;font-weight:700;font-size:8px">'+p.count.toLocaleString()+'</td></tr>').join('')+'</tbody></table>':'<div style="text-align:center;color:#95a5a6;font-size:9px;padding:20px">No FIM data</div>'}</div>
  </div>
</div>

